external_knowledge:
- 'experienced American players' refers to players with USA nationality;
- 'logged over a decade of competition' refers to players who have played more than 10 matches;
- 'consistently perform well, showing their skill by scoring above the basic standard' indicates players with an average score over 100;
- 'professional or amateur' status is considered in the player selection criteria;
- The players must have joined before January 1, 2022, to be included.

sql:
SELECT DISTINCT p.player_name
FROM players p
JOIN tournaments_players tp ON p.player_id = tp.player_id;

SELECT players.player_name, players.role
FROM players
WHERE players.player_id NOT IN (
    SELECT tournaments_players.player_id
    FROM tournaments_players
);

SELECT COUNT(*)
FROM tournaments_players
WHERE tournament_id = 1;

SELECT players.player_name, teams.team_name
FROM players
INNER JOIN teams ON players.player_id = teams.captain_id;

SELECT AVG(average_score) AS average_player_score
FROM player_stats
WHERE tournament_id = 1 AND wins > 5;

SELECT p.player_name, t.team_name
FROM players p
JOIN teams t ON p.player_id = t.captain_id;

SELECT player_id, average_score
FROM player_stats
WHERE average_score = (SELECT MAX(average_score) FROM player_stats);
